import CinematicSignboard from '@/components/CinematicSignboard';
import GameCharacterScreen from '@/components/game/GameCharacterScreen';
import GameInventoryScreen from '@/components/game/GameInventoryScreen';
import GameLocationScreen from '@/components/game/GameLocationScreen';
import GameMapScreen from '@/components/game/GameMapScreen';
import GameMenuScreen from '@/components/game/GameMenuScreen';
import GameStatusScreen from '@/components/game/GameStatusScreen';
import { useGameScreenStore } from '@/store/gameScreenStore';
import { useEffect, useRef, useState } from 'react';

export default function GamePage() {
  const currentScreen = useGameScreenStore((state) => state.currentScreen);
  const setScreen = useGameScreenStore((state) => state.setScreen);
  const [showCinematic, setShowCinematic] = useState(true);

  useEffect(() => {
    // Reset to menu screen when page loads
    setScreen('menu');

    // Show cinematic for 5 seconds on page load
    const timer = setTimeout(() => {
      setShowCinematic(false);
    }, 5000);

    return () => clearTimeout(timer);
  }, [setScreen]);

  if (showCinematic) {
    return (
      <div className="w-screen h-screen bg-black overflow-hidden">
        <CinematicSignboard />
      </div>
    );
  }

  return (
    <div className="w-screen h-screen bg-black overflow-hidden">
      {currentScreen === 'menu' && <GameMenuScreen />}
      {currentScreen === 'map' && <GameMapScreen />}
      {currentScreen === 'location' && <GameLocationScreen />}
      {currentScreen === 'character' && <GameCharacterScreen />}
      {currentScreen === 'inventory' && <GameInventoryScreen />}
      {currentScreen === 'status' && <GameStatusScreen />}
    </div>
  );
}

export default function GameMapScreen() {

  const mapRef = useRef(null);

    const [coords,setCoords] = useState({x:0,y:0});
      const [zoom,setZoom] = useState(1);
        const [position,setPosition] = useState({x:0,y:0});
          const [dragging,setDragging] = useState(false);
            const [startDrag,setStartDrag] = useState({x:0,y:0});

              const buildings = [
                  {name:"Barraco",x:300,y:600},
                      {name:"Cassino",x:800,y:420},
                          {name:"Delegacia",x:600,y:250},
                              {name:"Arsenal",x:1000,y:500},
                                  {name:"Prefeitura",x:500,y:350},
                                      {name:"Lavanderia",x:900,y:650}
                                        ];

                                          function handleMapClick(e){

                                              const rect = mapRef.current.getBoundingClientRect();

                                                  const x = Math.round((e.clientX - rect.left - position.x)/zoom);
                                                      const y = Math.round((e.clientY - rect.top - position.y)/zoom);

                                                          setCoords({x,y});

                                                              navigator.clipboard.writeText(`x:${x}, y:${y}`);

                                                                }

                                                                  function handleWheel(e){

                                                                      e.preventDefault();

                                                                          let newZoom = zoom - e.deltaY * 0.001;

                                                                              if(newZoom < 0.5) newZoom = 0.5;
                                                                                  if(newZoom > 2) newZoom = 2;

                                                                                      setZoom(newZoom);

                                                                                        }

                                                                                          function handleMouseDown(e){

                                                                                              setDragging(true);

                                                                                                  setStartDrag({
                                                                                                        x:e.clientX - position.x,
                                                                                                              y:e.clientY - position.y
                                                                                                                  });

                                                                                                                    }

                                                                                                                      function handleMouseMove(e){

                                                                                                                          if(!dragging) return;

                                                                                                                              setPosition({
                                                                                                                                    x:e.clientX - startDrag.x,
                                                                                                                                          y:e.clientY - startDrag.y
                                                                                                                                              });

                                                                                                                                                }

                                                                                                                                                  function handleMouseUp(){

                                                                                                                                                      setDragging(false);

                                                                                                                                                        }

                                                                                                                                                          return (

                                                                                                                                                              <div
                                                                                                                                                                    className="w-screen h-screen bg-black overflow-hidden"
                                                                                                                                                                          onWheel={handleWheel}
                                                                                                                                                                                onMouseMove={handleMouseMove}
                                                                                                                                                                                      onMouseUp={handleMouseUp}
                                                                                                                                                                                          >

                                                                                                                                                                                                <div
                                                                                                                                                                                                        ref={mapRef}
                                                                                                                                                                                                                onMouseDown={handleMouseDown}
                                                                                                                                                                                                                        onClick={handleMapClick}
                                                                                                                                                                                                                                style={{
                                                                                                                                                                                                                                          transform:`translate(${position.x}px,${position.y}px) scale(${zoom})`,
                                                                                                                                                                                                                                                    transformOrigin:"top left",
                                                                                                                                                                                                                                                              position:"relative",
                                                                                                                                                                                                                                                                        width:"2000px",
                                                                                                                                                                                                                                                                                  height:"2000px"
                                                                                                                                                                                                                                                                                          }}
                                                                                                                                                                                                                                                                                                >

                                                                                                                                                                                                                                                                                                        {/* MAPA */}

                                                                                                                                                                                                                                                                                                                <img
                                                                                                                                                                                                                                                                                                                          src="/mapa-cidade.png"
                                                                                                                                                                                                                                                                                                                                    style={{
                                                                                                                                                                                                                                                                                                                                                position:"absolute",
                                                                                                                                                                                                                                                                                                                                                            width:"100%",
                                                                                                                                                                                                                                                                                                                                                                        height:"100%",
                                                                                                                                                                                                                                                                                                                                                                                    objectFit:"cover"
                                                                                                                                                                                                                                                                                                                                                                                              }}
                                                                                                                                                                                                                                                                                                                                                                                                      />

                                                                                                                                                                                                                                                                                                                                                                                                              {/* GRID DEBUG */}

                                                                                                                                                                                                                                                                                                                                                                                                                      {[...Array(40)].map((_,i)=>(
                                                                                                                                                                                                                                                                                                                                                                                                                                <div
                                                                                                                                                                                                                                                                                                                                                                                                                                            key={"v"+i}
                                                                                                                                                                                                                                                                                                                                                                                                                                                        style={{
                                                                                                                                                                                                                                                                                                                                                                                                                                                                      position:"absolute",
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    left:i*50,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  top:0,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                width:1,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              height:"100%",
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            background:"rgba(255,255,255,0.05)"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        }}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          ))}

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  {[...Array(40)].map((_,i)=>(
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            <div
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        key={"h"+i}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    style={{
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  position:"absolute",
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                top:i*50,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              left:0,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            height:1,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          width:"100%",
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        background:"rgba(255,255,255,0.05)"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    }}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      ))}

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              {/* MARCADOR CLIQUE */}

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <div
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                style={{
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            position:"absolute",
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        left:coords.x,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    top:coords.y,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                width:20,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            height:20,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        background:"red",
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    borderRadius:"50%",
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                transform:"translate(-50%,-50%)",
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            pointerEvents:"none"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      }}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              />

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      {/* PRÉDIOS */}

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              {buildings.map((b,i)=>(

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <div
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    key={i}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                style={{
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              position:"absolute",
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            left:b.x,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          top:b.y,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        transform:"translate(-50%,-50%)",
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      textAlign:"center"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  }}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            >

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <img
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      src="/icons/building.png"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    style={{
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    width:40,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    cursor:"pointer"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  }}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              />

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <div
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        style={{
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        color:"white",
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        fontSize:12
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      }}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  >
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                {b.name}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            </div>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      </div>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              ))}

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    </div>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          {/* HUD DEBUG */}

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <div
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        style={{
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  position:"fixed",
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            top:20,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      left:20,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                background:"rgba(0,0,0,0.7)",
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          color:"white",
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    padding:10,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              borderRadius:8,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        fontSize:14
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                }}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      >

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              X: {coords.x}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <br/>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              Y: {coords.y}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <br/>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              Zoom: {zoom.toFixed(2)}

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    </div>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        </div>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          );

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          }
